// readWritePin implements read-after-write consistency: after a client writes an
// account, that account's reads are served from the primary until we can prove
// the replica has caught up to (at least) the version the client just wrote.
//
// The previous implementation pinned an account to the primary only for a fixed
// time window (TTL). That is unsound: replication lag is not bounded by any
// constant, so once the window expired a read could be routed to a replica that
// had not yet applied the write, returning a stale (pre-deposit) balance. To be
// correct, the pin must be released based on observed replica progress, not on
// wall-clock time alone.
//
// We track, per account, a monotonically increasing version that is bumped on
// every write. A read from the replica is only trusted once the replica's
// observed version is >= the last written version. Until then reads are served
// from the primary so the client always reads its own write.
type readWritePin struct {
	mu sync.Mutex
	// version is the latest write version we have issued for an account.
	version map[string]uint64
	// counter is a process-wide monotonic source for write versions.
	counter uint64
}

func newReadWritePin() *readWritePin {
	return &readWritePin{version: make(map[string]uint64)}
}

// mark records that the account was just written and returns the version
// assigned to that write.
func (p *readWritePin) mark(account string) uint64 {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.counter++
	p.version[account] = p.counter
	return p.counter
}

// pinned reports whether the account currently must be served from the primary.
func (p *readWritePin) pinned(account string) bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	_, ok := p.version[account]
	return ok
}

